// WebGPU compat test #9 — aether's RoPE WGSL kernels (BOTH variants) under monster.
//
// WGSL_ROPE (interleaved / llama 'pairs': rotate adjacent x[2k],x[2k+1]) and
// WGSL_ROPE_NEOX (qwen / GPT-NeoX rotate_half: rotate x[k], x[k+headDim/2])
// copied VERBATIM from open-source/aether/dist-browser/sovereign-shaders.js.
// Qwen2.5 needs the NeoX path, so this golden is load-bearing for the keystone.
// Two compute dispatches (one per variant) on the same known head buffer,
// golden-diffed monster vs the Deno real-navigator.gpu oracle.
//
// Inline pure-JS encoders (monster: no DataView, no cross-file ESM import).
// Output quantized to 1e-4 to absorb sub-ULP cos/sin/pow backend divergence.

function f32bytes(x) {
  if (x === 0) return [0, 0, 0, 0];
  const sign = x < 0 ? 1 : 0; x = Math.abs(x);
  let e = Math.floor(Math.log2(x)); let m = x / Math.pow(2, e);
  if (m < 1) { m *= 2; e -= 1; } if (m >= 2) { m /= 2; e += 1; }
  const bits = ((sign << 31) | ((e + 127) << 23) | Math.round((m - 1) * Math.pow(2, 23))) >>> 0;
  return [bits & 0xff, (bits >>> 8) & 0xff, (bits >>> 16) & 0xff, (bits >>> 24) & 0xff];
}
function bytesToF32(b0, b1, b2, b3) {
  const bits = ((b0) | (b1 << 8) | (b2 << 16) | (b3 << 24)) >>> 0;
  const sign = (bits >>> 31) & 1 ? -1 : 1; const exp = (bits >>> 23) & 0xff; const mant = bits & 0x7fffff;
  if (exp === 0) return sign * mant * Math.pow(2, -149);
  if (exp === 255) return mant ? NaN : sign * Infinity;
  return sign * (1 + mant / Math.pow(2, 23)) * Math.pow(2, exp - 127);
}
function u32bytes(v) { return [v & 0xff, (v >>> 8) & 0xff, (v >>> 16) & 0xff, (v >>> 24) & 0xff]; }
function q4(v) { const s = v < 0 ? -1 : 1; return s * Math.round(Math.abs(v) * 1e4) / 1e4; }

const out = {};
const adapter = await navigator.gpu.requestAdapter();
const device = await adapter.requestDevice();

// 2 heads, headDim 8, pos 3, theta 10000 (qwen rope_theta is 1e6 but 1e4 keeps
// the angles in a well-conditioned range for the golden; the kernel is the same).
const NUM_HEADS = 2, HEAD_DIM = 8, POS = 3.0, THETA = 10000.0;
const TOTAL = NUM_HEADS * HEAD_DIM;
function xval(i) { return ((i % 9) - 4) * 0.25; } // -1..1

// RopeDims { numHeads: u32, headDim: u32, pos: f32, theta: f32 }
const dimBytes = u32bytes(NUM_HEADS).concat(u32bytes(HEAD_DIM)).concat(f32bytes(POS)).concat(f32bytes(THETA));
const X_BYTES = TOTAL * 4;
const DIM_BYTES = 16;

function makeXBytes() {
  let b = [];
  for (let i = 0; i < TOTAL; i++) b = b.concat(f32bytes(xval(i)));
  return b;
}

const WGSL_ROPE = `
struct RopeDims { numHeads: u32, headDim: u32, pos: f32, theta: f32 };
@group(0) @binding(0) var<storage, read_write> x: array<f32>;
@group(0) @binding(1) var<uniform> d: RopeDims;
@compute @workgroup_size(64, 1, 1)
fn main(@builtin(global_invocation_id) gid: vec3<u32>) {
  let half = d.headDim / 2u;
  let total = d.numHeads * half;
  let idx = gid.x;
  if (idx >= total) { return; }
  let h = idx / half;
  let k = idx % half;
  let freq = pow(d.theta, -2.0 * f32(k) / f32(d.headDim));
  let ang = d.pos * freq;
  let c = cos(ang);
  let s = sin(ang);
  let base = h * d.headDim + 2u * k;
  let x0 = x[base];
  let x1 = x[base + 1u];
  x[base]      = x0 * c - x1 * s;
  x[base + 1u] = x0 * s + x1 * c;
}
`;
const WGSL_ROPE_NEOX = `
struct RopeDims { numHeads: u32, headDim: u32, pos: f32, theta: f32 };
@group(0) @binding(0) var<storage, read_write> x: array<f32>;
@group(0) @binding(1) var<uniform> d: RopeDims;
@compute @workgroup_size(64, 1, 1)
fn main(@builtin(global_invocation_id) gid: vec3<u32>) {
  let half = d.headDim / 2u;
  let total = d.numHeads * half;
  let idx = gid.x;
  if (idx >= total) { return; }
  let h = idx / half;
  let k = idx % half;
  let freq = pow(d.theta, -2.0 * f32(k) / f32(d.headDim));
  let ang = d.pos * freq;
  let c = cos(ang);
  let s = sin(ang);
  let base = h * d.headDim;
  let i0 = base + k;
  let i1 = i0 + half;
  let x0 = x[i0];
  let x1 = x[i1];
  x[i0] = x0 * c - x1 * s;
  x[i1] = x0 * s + x1 * c;
}
`;

const dBuf = device.createBuffer({ size: DIM_BYTES, usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(dBuf, 0, new Uint8Array(dimBytes));

async function runRope(code) {
  const xBuf = device.createBuffer({ size: X_BYTES, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST | GPUBufferUsage.COPY_SRC });
  device.queue.writeBuffer(xBuf, 0, new Uint8Array(makeXBytes()));
  const shader = device.createShaderModule({ code });
  const pipeline = device.createComputePipeline({ layout: 'auto', compute: { module: shader, entryPoint: 'main' } });
  const bindGroup = device.createBindGroup({
    layout: pipeline.getBindGroupLayout(0),
    entries: [{ binding: 0, resource: { buffer: xBuf } }, { binding: 1, resource: { buffer: dBuf } }],
  });
  const enc = device.createCommandEncoder();
  const pass = enc.beginComputePass();
  pass.setPipeline(pipeline);
  pass.setBindGroup(0, bindGroup);
  pass.dispatchWorkgroups(1, 1, 1);
  pass.end();
  const readBuf = device.createBuffer({ size: X_BYTES, usage: GPUBufferUsage.COPY_DST | GPUBufferUsage.MAP_READ });
  enc.copyBufferToBuffer(xBuf, 0, readBuf, 0, X_BYTES);
  device.queue.submit([enc.finish()]);
  await readBuf.mapAsync(GPUMapMode.READ);
  const px = new Uint8Array(readBuf.getMappedRange());
  let r = [];
  for (let i = 0; i < TOTAL; i++) { const o = i * 4; r = r.concat([bytesToF32(px[o], px[o + 1], px[o + 2], px[o + 3])]); }
  readBuf.unmap();
  return r;
}

// CPU references (mirror the two WGSL variants exactly).
function ropeInterleavedCPU() {
  let x = []; for (let i = 0; i < TOTAL; i++) x = x.concat([xval(i)]);
  const half = HEAD_DIM / 2;
  for (let h = 0; h < NUM_HEADS; h++) {
    for (let k = 0; k < half; k++) {
      const freq = Math.pow(THETA, -2.0 * k / HEAD_DIM);
      const ang = POS * freq;
      const cc = Math.cos(ang);
      const ss = Math.sin(ang);
      const base = h * HEAD_DIM + 2 * k;
      const x0 = x[base];
      const x1 = x[base + 1];
      x[base] = x0 * cc - x1 * ss; x[base + 1] = x0 * ss + x1 * cc;
    }
  }
  return x;
}
function ropeNeoxCPU() {
  let x = []; for (let i = 0; i < TOTAL; i++) x = x.concat([xval(i)]);
  const half = HEAD_DIM / 2;
  for (let h = 0; h < NUM_HEADS; h++) {
    for (let k = 0; k < half; k++) {
      const freq = Math.pow(THETA, -2.0 * k / HEAD_DIM);
      const ang = POS * freq;
      const cc = Math.cos(ang);
      const ss = Math.sin(ang);
      const base = h * HEAD_DIM;
      const i0 = base + k;
      const i1 = i0 + half;
      const x0 = x[i0];
      const x1 = x[i1];
      x[i0] = x0 * cc - x1 * ss; x[i1] = x0 * ss + x1 * cc;
    }
  }
  return x;
}

const gpuInter = await runRope(WGSL_ROPE);
const gpuNeox = await runRope(WGSL_ROPE_NEOX);
const cpuInter = ropeInterleavedCPU();
const cpuNeox = ropeNeoxCPU();

out.interleavedGpu = gpuInter.map(q4);
out.interleavedCpu = cpuInter.map(q4);
out.neoxGpu = gpuNeox.map(q4);
out.neoxCpu = cpuNeox.map(q4);
console.error('RAW interGpu=' + JSON.stringify(gpuInter.slice(0, 4)) + ' neoxGpu=' + JSON.stringify(gpuNeox.slice(0, 4)));
console.log('__RESULT__ ' + JSON.stringify(out));
